import"./CWj6FrbW.js";import"./DaVP5oC0.js";import{f as i,a as o,a5 as n}from"./CSwRgDnd.js";const a={title:"Erasmus+ DREAMER Team Visits Poland, Hosted by Kozminski University | 27–31 Oct 2025",date:"31.10.2025",categories:["events"],gallery:"study-visit-poland",published:!0},{title:d,date:c,categories:u,gallery:p,published:m}=a;var r=i(`<p><strong>Study Tour in Warsaw - Behind Us!</strong></p> <p>Another intensive week of the DREAMER project is behind us. This time, together with our international consortium partners, we gathered at <a href="https://www.kozminski.edu.pl/en" rel="nofollow">Kozminski University</a> in Warsaw for a series of productive sessions combining research work with practical industry insights.
Beyond the intensive work of project teams, we organized a series of master classes and a seminar featuring:</p> <ul><li><a href="https://www.linkedin.com/in/robert-kiedry" rel="nofollow">Robert Kiedryński</a>, BIM Coordinator from p<a href="https://budimex.pl/en/" rel="nofollow">Budimex</a> presenting „The Use of BIM Methodology at Budimex”</li> <li><a href="https://legally-designed.com/en/" rel="nofollow">Legally.Designed</a> team (<a href="https://www.linkedin.com/in/ninaidzik/" rel="nofollow">Nina Idzik</a> & <a href="https://www.linkedin.com/in/zofiatykwinskasutkowska/" rel="nofollow">Zofia Tykwińska-Sutkowska</a>) sharing their insights on „Wellbeing Culture and Communication within Agile Teams - How to design psychologically sustainable collaboration in agile environments”</li></ul> <p>The highlight of our study tour was a site visit at the Warszawa Zachodnia railway station construction project. We had the opportunity to witness firsthand the phenomenal strategies Budimex employs to respond to construction challenges without putting the investment at risk. The alternative solutions implemented on this project are truly commendable and worth recognizing!</p> <p>The knowledge and best practices we’re gathering through this study tour will directly support the reconstruction of Ukraine, while also contributing significantly to construction process management in other markets.
I’m grateful to be part of this international collaboration that brings together academics, engineers, and industry practitioners from across Europe. The DREAMER: Development and Reconstruction Empowerment through Advanced Project Management Education and Research project continues to deliver valuable insights that will shape the future of construction project management.</p> <p>A big thank you to Kozminski University for hosting us and to all the speakers and participants for their valuable contributions!</p>`,1);function g(e){var t=r();n(10),o(e,t)}export{g as default,a as metadata};
